var red = core.vec3f(1.0, 0.0, 0.0);
HighlightMgr.setColor(red);
core.debug('Highlight color changed to red');

var cyan = core.vec3f(0.0, 1.0, 1.0);
HighlightMgr.setColor(cyan);
core.debug('Highlight color changed to cyan');

var color = HighlightMgr.getColor();
core.debug('Current highlight color - R: ' + color[0] + ', G: ' + color[1] + ', B: ' + color[2]);

if(color[0] > 0.8 && color[1] < 0.2 && color[2] < 0.2) {
    core.debug('Highlights are red');
}

HighlightMgr.setMarkersSize(15.0);
core.debug('Highlight marker size set to 15 pixels');

HighlightMgr.setMarkersSize(11.0);
core.debug('Highlight marker size reset to default (11 pixels)');

// Add a highlight at Orion Nebula
HighlightMgr.addPoint('5h 35m 17.3s', '-5° 23′ 28″');
core.debug('Highlight added at Orion Nebula');

// Add multiple highlights
HighlightMgr.addPoint('5h 35m 17.3s', '-5° 23′ 28″');
HighlightMgr.addPoint('5h 35m 20.0s', '-5° 25′ 00″');
core.debug('Added multiple highlights');

// Add a highlight at current date coordinates
HighlightMgr.addPointRaDec('2h 10m 15s', '60d 01m 15s');
core.debug('Highlight added using current date coordinates');

// Add a highlight at the Sun's current position
var sunInfo = core.getObjectInfo('Sun');
if(sunInfo) {
    HighlightMgr.addPointRaDec(sunInfo['ra'], sunInfo['dec']);
    core.debug('Highlight added at Sun\'s current position');
}

// Add a highlight at zenith (directly overhead)
HighlightMgr.addPointAltAzi('90°', '0°');
core.debug('Highlight added at zenith');

// Add a highlight on the eastern horizon
HighlightMgr.addPointAltAzi('0°', '90°');
core.debug('Highlight added on eastern horizon');

// Add a highlight on the southern meridian at 45° altitude
HighlightMgr.addPointAltAzi('45d', '180d');
core.debug('Highlight added at 45° altitude, south direction');

// Clear all highlight markers
HighlightMgr.cleanHighlightList();
core.debug('All highlight markers removed');

// Add markers then clear them
HighlightMgr.addPoint('2h 10m 15s', '60d 01m 15s');
HighlightMgr.addPoint('4h 20m 30s', '30d 15m 00s');
core.debug('Added two highlights');
core.wait(3);
HighlightMgr.cleanHighlightList();
core.debug('Highlights cleared after 3 seconds');

// Create a list of positions
var positions = [];
var pos1 = core.vec3d(0.5, 0.5, 0.707);
var pos2 = core.vec3d(0.2, 0.8, 0.566);
positions.push(pos1);
positions.push(pos2);

// Replace all highlights with the new list
HighlightMgr.fillHighlightList(positions);
core.debug('Highlight list replaced with ' + positions.length + ' positions');

// Clear all highlights by passing an empty list
HighlightMgr.fillHighlightList([]);
core.debug('All highlights cleared via empty list');
